import base64, os
from pathlib import Path

os.makedirs("src-tauri/icons", exist_ok=True)

icons = {
    "icon.ico": "",
    "icon.png": "",
    "128x128.png": "",
    "32x32.png": "",
}

for filename, b64data in icons.items():
    Path(f"src-tauri/icons/{filename}").write_bytes(
        base64.b64decode(b64data)
    )
    print(f"Created: src-tauri/icons/{filename}")
